const trigger = $('Trigger').first().json || {};
const tenant = $input.first().json || {};

const normalize = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  const txt = String(v).trim();
  return txt || fallback;
};

const normalizePhone = (v) => normalize(v).replace(/[^0-9]/g, '');

const categoria = normalize(trigger.categoria, 'sem_categoria');
const urgencia = normalize(trigger.urgencia, 'media').toLowerCase();
const patientPhone = normalizePhone(trigger.patient_phone || trigger.telefone || trigger.phone);
const patientName = normalize(trigger.patient_name, 'Não informado');
const sessionId = normalize(trigger.session_id, 'N/A');
const resumo = normalize(trigger.resumo, 'Sem resumo adicional');
const mensagemUsuario = normalize(trigger.mensagem_usuario, 'Não informada');
const teamEmail = normalize(tenant.team_email, 'contato@bahiatecnologia.com.br');
const teamWhatsapp = normalizePhone(tenant.team_whatsapp);
const senderPhoneNumberId = normalize(trigger.sender_phone_number_id);
const nowBr = new Date().toLocaleString('pt-BR');

const assunto = `📣 Recado do Assistente (${categoria}) - ${tenant.owner_name || 'Clínica'} - ${nowBr}`;

const corpoEmail = [
  `Recado automático enviado pelo assistente virtual ${tenant.ai_assistant_name || 'Assistente'}.`,
  '',
  `Categoria: ${categoria}`,
  `Urgência: ${urgencia}`,
  `Paciente: ${patientName}`,
  `Telefone do paciente: ${patientPhone || 'Não informado'}`,
  `Sessão: ${sessionId}`,
  `Resumo: ${resumo}`,
  `Mensagem do usuário: ${mensagemUsuario}`,
  '',
  `Data/Hora: ${nowBr}`
].join('\n');

const corpoWhatsapp = [
  '📣 *Recado do assistente virtual*',
  `*Categoria:* ${categoria}`,
  `*Urgência:* ${urgencia}`,
  `*Paciente:* ${patientName}`,
  `*Telefone:* ${patientPhone || 'Não informado'}`,
  `*Sessão:* ${sessionId}`,
  `*Resumo:* ${resumo}`,
  `*Mensagem do usuário:* ${mensagemUsuario}`,
  `*Data/Hora:* ${nowBr}`
].join('\n');

return [{
  json: {
    tenant_code: tenant.tenant_code || null,
    schema_name: tenant.schema_name || trigger.schema_name || null,
    owner_name: tenant.owner_name || null,
    ai_assistant_name: tenant.ai_assistant_name || null,
    categoria,
    urgencia,
    patient_phone: patientPhone || null,
    patient_name: patientName,
    session_id: sessionId,
    mensagem_usuario: mensagemUsuario,
    resumo,
    team_email: teamEmail,
    team_whatsapp: teamWhatsapp || null,
    sender_phone_number_id: senderPhoneNumberId || null,
    email_subject: assunto,
    email_body: corpoEmail,
    whatsapp_body: corpoWhatsapp
  }
}];

const base = $('Preparar Recado').first().json || {};

const enviadoNoWhatsapp = !!base.team_whatsapp && !!base.sender_phone_number_id;

return [{
  json: {
    resultado: enviadoNoWhatsapp
      ? `Recado enviado para o time humano por e-mail (${base.team_email}) e WhatsApp (${base.team_whatsapp}).`
      : `Recado enviado para o time humano por e-mail (${base.team_email}). WhatsApp não foi enviado por falta de configuração (team_whatsapp ou sender_phone_number_id).`,
    status: 'ok',
    canais: {
      email: 'enviado',
      whatsapp: enviadoNoWhatsapp ? 'enviado' : 'nao_configurado'
    },
    destino: {
      email: base.team_email || null,
      whatsapp: base.team_whatsapp || null
    },
    payload: {
      categoria: base.categoria || null,
      urgencia: base.urgencia || null,
      paciente: {
        nome: base.patient_name || null,
        telefone: base.patient_phone || null
      },
      resumo: base.resumo || null,
      mensagem_usuario: base.mensagem_usuario || null
    }
  }
}];
